// modules/notifications/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'notifications',
  description: 'Handles user notifications and provides utilities for managing them.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'GET', path: '/notifications', auth: true },
    ],
    functions: ['getNotifications'],
    types: ['Notification'],
  },

  sideEffects: [
    'reads from: notifications table',
  ],

  invariants: [
    'A user can have multiple unread notifications',
    'Read notifications should be marked as read immediately upon retrieval',
  ],
});

// modules/notifications/lib/types.ts
export interface Notification {
  id: number;
  userId: number;
  content: string;
  isRead: boolean;
  createdAt: Date;
}

// modules/notifications/lib/db.ts
import { query } from '../lib/db';

export async function getNotifications(userId: number, page: number = 1, pageSize: number = 10): Promise<Notification[]> {
  const offset = (page - 1) * pageSize;
  const result = await query(`
    SELECT * FROM notifications
    WHERE user_id = $1 AND is_read = false
    ORDER BY created_at DESC
    LIMIT $2 OFFSET $3
  `, [userId, pageSize, offset]);
  return result.rows as Notification[];
}

// modules/notifications/routes/index.ts
import { Router } from 'bun';
import { requireUser } from '../lib/auth';
import { getNotifications } from '../lib/db';

const router = new Router();

router.get('/notifications', async (req) => {
  const user = await requireUser(req);
  const page = parseInt(req.query.page || '1');
  const pageSize = parseInt(req.query.pageSize || '10');

  try {
    const notifications = await getNotifications(user.id, page, pageSize);
    return new Response(JSON.stringify(notifications), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: 'Failed to fetch notifications' }), { status: 500 });
  }
});

export default router;

// modules/notifications/lib/result.ts
import { Result, ok, err } from '../lib/result';

export async function getNotificationsResult(userId: number, page: number = 1, pageSize: number = 10): Promise<Result<Notification[], string>> {
  try {
    const notifications = await getNotifications(userId, page, pageSize);
    return ok(notifications);
  } catch (error) {
    return err('Failed to fetch notifications');
  }
}

// modules/notifications/lib/auth.ts
import { requireUser } from '../lib/auth';

export async function getNotificationsAuth(req: Request): Promise<Notification[]> {
  const user = await requireUser(req);
  return getNotifications(user.id);
}

